module counter_12(
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk) begin
        if (!rst_n)
            out <= 4'b0000;
        else if (valid_count && out == 4'd11)
            out <= 4'b0000;
        else if (valid_count)
            out <= out + 4'b0001;
    end
endmodule
